script.text:
      /* <flatten type="Javascript"> */
function load$AutoGenerateStocktaking(g) {
  g.add_onResponseComplete(on$AutoGenerateStocktaking$ResponseComplete);
  g.add_commandEvent(on$AutoGenerateStocktaking$ExecuteCommand);
  g._$cSite = g._getColumnOrder('ma_kho');
  g._$cSiteName = g._getColumnOrder('ten_kho');
  g._$cSiteLocation = g._getColumnOrder('vi_tri_yn');
  g._$cItem = g._getColumnOrder('ma_vt');
  g._$cItemName = g._getColumnOrder('ten_vt');
  g._$cItemLot = g._getColumnOrder('lo_yn');
  g._$cLocation = g._getColumnOrder('ma_vi_tri_x');
  g._$cLocationName = g._getColumnOrder('ten_vi_tri');
  g._$cLot = g._getColumnOrder('ma_lo_x');
  g._$cLotName = g._getColumnOrder('ten_lo');
  g._$cVal = g._getColumnOrder('gia_ton');
  g._$cVarQty = g._getColumnOrder('sl_cl');
}
function dispose$AutoGenerateStocktaking(g) {
  try {g.remove_commandEvent(on$AutoGenerateStocktaking$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$AutoGenerateStocktaking$ResponseComplete);} catch (ex) {}
}
function on$AutoGenerateStocktaking$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'CreateStocktaking':
      if (g._rowCount == 0) break;
      g.showForm('AutoGenerateStocktakingCreate');
      break;
    case 'Edit':
      e.type.cancelEvent = true;
      g.showForm('AutoGenerateStocktakingUpdate');
      break;
    case 'DeleteStocktaking':
      request$AutoGenerateStocktaking$(g, action);
      break;
    case 'Delete':
      e.type.cancelEvent = true;
      request$AutoGenerateStocktaking$(g, action);
      break;
    default:
      break;
  }
}
function on$AutoGenerateStocktaking$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, id = g.get_id(), v = g._language == 'v', mess;
  switch (context) {
    case 'DeleteStocktaking':
      if (result[0].Value == '1') {
        mess = (v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.');
      } else {
        mess = ((result[1].Value).indexOf('$NotAuthorized') != -1 ? $df.getResources(g._language, "Message.NotAccess") : result[1].Value);
      }
      $message.show(mess, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    case 'Delete':
      if (result[0].Value == '0') $message.show($df.getResources(g._language, "Message.NotAccess"));
        else g.goToPage(-1);
      break;
    default:
      break;
  }
}
function request$AutoGenerateStocktaking$(g, c) {
  if (g._rowCount == 0 && c == 'Delete') return;
  var r = (g._activeCell ? g._activeRow : 1), site = g._$s, a = [];

  Array.add(a, ['stt_rec', 'String', g._$k]);
  Array.add(a, ['ma_dvcs', 'String', g._$u]);
  Array.add(a, ['type', 'String', g._$t]);
  if (c == 'Delete') {
    site = g._getItemValue(r, g._$cSite);
    Array.add(a, ['ma_vt', 'String', g._getItemValue(r, g._$cItem)]);
    Array.add(a, ['ma_vi_tri_x', 'String', g._getItemValue(r, g._$cLocation)]);
    Array.add(a, ['ma_lo_x', 'String', g._getItemValue(r, g._$cLot)]);
    Array.add(a, ['ma_vi_tri', 'String', g._getItemValue(r, g._getColumnOrder('ma_vi_tri'))]);
    Array.add(a, ['ma_lo', 'String', g._getItemValue(r, g._getColumnOrder('ma_lo'))]);
  }
  Array.add(a, ['ma_kho', 'String', site]);
  g.request(g, c, c, a)
}
/* </flatten> */
      &JavascriptReportInit;
